queries.sparql:
PREFIX : <http://ambrosia.example.org/agriculture#>
PREFIX p: <http://ambrosia.example.org/agriculture/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?area_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFocus_Areas ?child ; p:hasAgricultural_Research_Institutes ?parent . } GROUP BY ?child }
  ?child p:name ?area_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Agricultural_Research_Institutes } }
  FILTER(?nf = ?total)
}

